function money(v) { return Number(v || 0).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }) }

function makeMonthDays() {
  const weeks = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb']
  const months = ['jan', 'fev', 'mar', 'abr', 'mai', 'jun', 'jul', 'ago', 'set', 'out', 'nov', 'dez']
  return Array.from({ length: 30 }, (_, i) => {
    const date = new Date(); date.setDate(date.getDate() + i)
    return { id: `d${i}`, week: i === 0 ? 'Hoje' : weeks[date.getDay()], day: String(date.getDate()).padStart(2, '0'), label: `${String(date.getDate()).padStart(2, '0')} ${months[date.getMonth()]}` }
  })
}

function badgeStyle(status) {
  if (status === 'Confirmado') return { background: '#dcfce7', color: '#166534' }
  if (status === 'Pendente') return { background: '#fef3c7', color: '#92400e' }
  if (status === 'Cancelado' || status === 'Recusado') return { background: '#fee2e2', color: '#991b1b' }
  return { background: '#f1f5f9', color: '#334155' }
}

function AnimatedNumber({ value, suffix = '', prefix = '' }) {
  const [current, setCurrent] = useState(0)
  const [started, setStarted] = useState(false)
  const ref = useRef(null)
  useEffect(() => {
    const el = ref.current
    if (!el) return
    const obs = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) setStarted(true)
      else { setStarted(false); setCurrent(0) }
    }, { threshold: 0.45 })
    obs.observe(el)
    return () => obs.disconnect()
  }, [])
  useEffect(() => {
    if (!started) return
    const target = Number(value)
    let start = 0
    const step = Math.max(1, Math.ceil(target / 55))
    const timer = setInterval(() => {
      start += step
      if (start >= target) { setCurrent(target); clearInterval(timer) } else setCurrent(start)
    }, 18)
    return () => clearInterval(timer)
  }, [value, started])
  return <span ref={ref} className={`countSpin ${started ? 'spinOn' : ''}`}>{prefix}{current}{suffix}</span>
}

