  const promos = services.filter(s => s.promo && Number(s.promoPrice) > 0 && s.id !== Number(form.serviceId))
  const confirmed = agenda.filter(a => a.status === 'Confirmado')
  const revenue = confirmed.reduce((s, a) => s + Number(a.value || 0), 0)
  const pending = agenda.filter(a => a.status === 'Pendente')
